3_real_world_example.code:
const myPromise = new Promise((resolve, reject) => {
  // State: Pending
  setTimeout(() => {
    resolve('Success!'); // Transitions to Fulfilled
    resolve('Ignored!'); // Ignored (already settled)
    reject('Error!');    // Ignored (already settled)
  }, 1000);
});

// Synchronous log: prints Promise { <pending> }
console.log(myPromise);

myPromise.then(result => {
  // Runs after 1 sec
  console.log('Result:', result); // 'Success!'
  // State is now Fulfilled. It will never change.
});

